     297:                      AV_TX_FLOAT_RDFT, 0, 1 << (nlevels + 1), &scale, 0);
     298:     if (ret < 0)
     299:         goto fail;
     300: 
     301:     ret = av_tx_init(&atempo->complex_to_real, &atempo->c2r_fn,
     302:                      AV_TX_FLOAT_RDFT, 1, 1 << (nlevels + 1), &iscale, 0);
     303:     if (ret < 0)
     304:         goto fail;
