    3376:         avio_wb32(pb, sgpd_entries[i].count); /* sample_count */
    3377:         avio_wb32(pb, sgpd_entries[i].group_description_index); /* group_description_index */
    3378:     }
    3379: 
    3380:     av_free(sgpd_entries);
    3381:     return 0;
    3382: }

