      43: static int pdv_read_header(AVFormatContext *s)
      44: {
      45:     PDVDemuxContext *p = s->priv_data;
      46:     AVIOContext *pb = s->pb;
      47:     AVCodecParameters *par;
      48:     AVStream *st;
      49:     uint64_t start;
      50:     uint32_t fps;
      51: 
      52:     avio_skip(pb, 16);
      53: 
      54:     st = avformat_new_stream(s, NULL);
      55:     if (!st)
      56:         return AVERROR(ENOMEM);
      57: 
      58:     par              = st->codecpar;
      59:     par->codec_type  = AVMEDIA_TYPE_VIDEO;
      60:     par->codec_id    = AV_CODEC_ID_PDV;
      61:     st->start_time   = 0;
      62:     st->duration     =
      63:     st->nb_frames    = avio_rl16(pb);
      64:     avio_skip(pb, 2);
      65:     fps = avio_rl32(pb);
      66:     st->avg_frame_rate = av_d2q(av_int2float(fps), INT_MAX);
      67:     par->width       = avio_rl16(pb);
      68:     par->height      = avio_rl16(pb);
      69: 
      70:     avpriv_set_pts_info(st, 64, st->avg_frame_rate.den, st->avg_frame_rate.num);
      71: 
      72:     p->current_frame = 0;
>>    73:     p->frame_flags = av_calloc(st->nb_frames + 1, sizeof(*p->frame_flags));
      74:     p->frame_offsets = av_calloc(st->nb_frames + 1, sizeof(*p->frame_offsets));
      75: 
      76:     if (!p->frame_flags || !p->frame_offsets)
      77:         return AVERROR(ENOMEM);
      78: 
      79:     for (int n = 0; n <= st->nb_frames; n++) {
      80:         const uint32_t entry = avio_rl32(pb);
      81: 
      82:         p->frame_flags[n] = entry & 3;
      83:         p->frame_offsets[n] = entry >> 2;
      84:     }
      85: 
      86:     start = avio_tell(pb);
      87: 
      88:     for (int n = 0; n < st->nb_frames; n++) {
      89:         const uint64_t pos = start + p->frame_offsets[n];
      90:         const int32_t size = p->frame_offsets[n+1] - p->frame_offsets[n];
      91:         const int flags = p->frame_flags[n] & 1 ? AVINDEX_KEYFRAME : 0;
      92: 
      93:         if (p->frame_flags[n] == 0 || size <= 0 ||
      94:             ((pb->seekable & AVIO_SEEKABLE_NORMAL) && pos + size > avio_size(pb)))
      95:             break;
      96:         av_add_index_entry(st, pos, n, size, 0, flags);
      97:     }
      98: 
      99:     return 0;
     100: }

     112: static int pp_bnk_read_header(AVFormatContext *s)
     113: {
     114:     int64_t ret;
     115:     AVStream *st;
     116:     AVCodecParameters *par;
     117:     PPBnkCtx *ctx = s->priv_data;
     118:     uint8_t buf[FFMAX(PP_BNK_FILE_HEADER_SIZE, PP_BNK_TRACK_SIZE)];
     119:     PPBnkHeader hdr;
     120: 
     121:     if ((ret = ffio_read_size(s->pb, buf, PP_BNK_FILE_HEADER_SIZE)) < 0)
     122:         return ret;
     123: 
     124:     pp_bnk_parse_header(&hdr, buf);
     125: 
     126:     if (hdr.track_count == 0 || hdr.track_count > INT_MAX)
     127:         return AVERROR_INVALIDDATA;
     128: 
     129:     if (hdr.sample_rate == 0 || hdr.sample_rate > INT_MAX)
     130:         return AVERROR_INVALIDDATA;
     131: 
     132:     if (hdr.always1 != 1) {
     133:         avpriv_request_sample(s, "Non-one header value");
     134:         return AVERROR_PATCHWELCOME;
     135:     }
     136: 
     137:     ctx->track_count = hdr.track_count;
     138: 
>>   139:     if (!(ctx->tracks = av_malloc_array(hdr.track_count, sizeof(PPBnkCtxTrack))))
     140:         return AVERROR(ENOMEM);
     141: 
     142:     /* Parse and validate each track. */
     143:     for (int i = 0; i < hdr.track_count; i++) {
     144:         PPBnkTrack e;
     145:         PPBnkCtxTrack *trk = ctx->tracks + i;
     146: 
     147:         ret = avio_read(s->pb, buf, PP_BNK_TRACK_SIZE);
     148:         if (ret < 0 && ret != AVERROR_EOF)
     149:             return ret;
     150: 
     151:         /* Short byte-count or EOF, we have a truncated file. */
     152:         if (ret != PP_BNK_TRACK_SIZE) {
     153:             av_log(s, AV_LOG_WARNING, "File truncated at %d/%u track(s)\n",
     154:                    i, hdr.track_count);
     155:             ctx->track_count = i;
     156:             break;
     157:         }
     158: 
     159:         pp_bnk_parse_track(&e, buf);
     160: 
     161:         /* The individual sample rates of all tracks must match that of the file header. */
     162:         if (e.sample_rate != hdr.sample_rate)
     163:             return AVERROR_INVALIDDATA;
     164: 
     165:         if (e.always1_1 != 1 || e.always1_2 != 1) {
     166:             avpriv_request_sample(s, "Non-one track header values");
     167:             return AVERROR_PATCHWELCOME;
     168:         }
     169: 
     170:         trk->data_offset = avio_tell(s->pb);
     171:         trk->data_size   = e.size;
     172:         trk->bytes_read  = 0;
     173: 
     174:         /*
     175:          * Skip over the data to the next stream header.
     176:          * Sometimes avio_skip() doesn't detect EOF. If it doesn't, either:
     177:          *   - the avio_read() above will, or
     178:          *   - pp_bnk_read_packet() will read a truncated last track.
     179:          */
     180:         if ((ret = avio_skip(s->pb, e.size)) == AVERROR_EOF) {
     181:             ctx->track_count = i + 1;
     182:             av_log(s, AV_LOG_WARNING,
     183:                    "Track %d has truncated data, assuming track count == %d\n",
     184:                    i, ctx->track_count);
     185:             break;
     186:         } else if (ret < 0) {
     187:             return ret;
     188:         }
     189:     }
     190: 
     191:     /* File is only a header. */
     192:     if (ctx->track_count == 0)
     193:         return AVERROR_INVALIDDATA;
     194: 
     195:     ctx->is_music = (hdr.flags & PP_BNK_FLAG_MUSIC) &&
     196:                     (ctx->track_count == 2) &&
     197:                     (ctx->tracks[0].data_size == ctx->tracks[1].data_size);
     198: 
     199:     /* Build the streams. */
     200:     for (int i = 0; i < (ctx->is_music ? 1 : ctx->track_count); i++) {
     201:         if (!(st = avformat_new_stream(s, NULL)))
     202:             return AVERROR(ENOMEM);
     203: 
     204:         par                         = st->codecpar;
     205:         par->codec_type             = AVMEDIA_TYPE_AUDIO;
     206:         par->codec_id               = AV_CODEC_ID_ADPCM_IMA_CUNNING;
     207:         par->format                 = AV_SAMPLE_FMT_S16P;
     208: 
     209:         av_channel_layout_default(&par->ch_layout, ctx->is_music + 1);
     210:         par->sample_rate            = hdr.sample_rate;
     211:         par->bits_per_coded_sample  = 4;
     212:         par->block_align            = 1;
     213:         par->bit_rate               = par->sample_rate * (int64_t)par->bits_per_coded_sample *
     214:                                       par->ch_layout.nb_channels;
     215: 
     216:         avpriv_set_pts_info(st, 64, 1, par->sample_rate);
     217:         st->start_time              = 0;
     218:         st->duration                = ctx->tracks[i].data_size * 2;
     219:     }
     220: 
     221:     return 0;
     222: }

     500: static int latm_context2config(AVFormatContext *s, const AVCodecParameters *par,
     501:                                char **out)
     502: {
     503:     /* MP4A-LATM
     504:      * The RTP payload format specification is described in RFC 3016
     505:      * The encoding specifications are provided in ISO/IEC 14496-3 */
     506: 
     507:     uint8_t config_byte[6];
     508:     int rate_index;
     509:     char *config;
     510: 
     511:     *out = NULL;
     512: 
     513:     for (rate_index = 0; rate_index < 16; rate_index++)
     514:         if (ff_mpeg4audio_sample_rates[rate_index] == par->sample_rate)
     515:             break;
     516:     if (rate_index == 16) {
     517:         av_log(s, AV_LOG_ERROR, "Unsupported sample rate\n");
     518:         return AVERROR(ENOSYS);
     519:     }
     520: 
     521:     config_byte[0] = 0x40;
     522:     config_byte[1] = 0;
     523:     config_byte[2] = 0x20 | rate_index;
     524:     config_byte[3] = par->ch_layout.nb_channels << 4;
     525:     config_byte[4] = 0x3f;
     526:     config_byte[5] = 0xc0;
     527: 
>>   528:     config = av_malloc(6*2+1);
     529:     if (!config) {
     530:         av_log(s, AV_LOG_ERROR, "Cannot allocate memory for the config info.\n");
     531:         return AVERROR(ENOMEM);
     532:     }
     533:     ff_data_to_hex(config, config_byte, 6, 1);
     534: 
     535:     *out = config;
